function y = fabius(varargin)
% fabius(x, d) for vector x, integer d
% fabius(x) for vector x, integer d = 0
% d = 0 : fabius function
% d > 0 : d-th derivative
% d < 0 : (-d)-th antiderivative

if nargin == 1
x = varargin{1};
d = 0;
elseif nargin == 2
x = varargin{1};
d = varargin{2};
else
error('fabius:InvalidNargin', ...
'Use fabius(x) or fabius(x, d).');
end

if ~(isscalar(d) && isfinite(d) && d == fix(d))
error('fabius:InvalidOrder', 'd must be a finite integer scalar.');
end
if ~isreal(x)
error('fabius:ComplexInput', 'x must be real.');
end

x = double(x);

if d == 0
y = local_f0(x);
y(isnan(x)) = NaN;
return;
end

if d > 0
y = zeros(size(x));
in01 = (x > 0.0) & (x < 1.0);
if any(in01(:))
u = x(in01);
total_pow = d*(d + 1)/2;
amp = pow2(1.0, total_pow);
sgn = ones(size(u));
for m = d:-1:1
if mod(m, 2) == 0
sgn(u > 0.5) = -sgn(u > 0.5);
end
u = 2.0.*min(u, 1.0 - u);
end
y(in01) = amp.*sgn.*local_f0(u);
end
y(isnan(x)) = NaN;
return;
end

n = -d;
y = zeros(size(x));

in01 = (x > 0.0) & (x < 1.0);
if any(in01(:))
scale_pow = n*(n - 1)/2;
y(in01) = pow2(1.0, scale_pow) .* fab_eval(pow2(x(in01), -n));
end

ge1 = x >= 1.0;
if any(ge1(:))
coeff = local_tail_coefficients(antiderivative_one(n));
t = x(ge1) - 1.0;
y(ge1) = local_polyval_ascending(coeff, t);
end

y(isnan(x)) = NaN;
end

function y = local_f0(x)
y = zeros(size(x));
y(x >= 1.0) = 1.0;

in01 = (x > 0.0) & (x < 1.0);
if any(in01(:))
xi = x(in01);
r = xi > 0.5;

xe = xi;
xe(r) = 1.0 - xe(r);

yi = fab_eval(xe);
yi(r) = 1.0 - yi(r);

y(in01) = yi;
end
end

function m = antiderivative_one(n)
m = zeros(1, n + 1);
m(1) = 1.0;
scale = 1.0;
for j = 1:n
if j > 1
scale = scale * pow2(1.0, j - 1);
end
m(j + 1) = scale * fab_eval(pow2(1.0, -j));
end
end

function coeff = local_tail_coefficients(m)
n = numel(m) - 1;
coeff = 1.0;
for j = 1:n
next = zeros(1, j + 1);
next(1) = m(j + 1);
next(2:end) = coeff ./ (1:j);
coeff = next;
end
end

function y = local_polyval_ascending(coeff, t)
y = coeff(end).*ones(size(t));
for k = numel(coeff)-1:-1:1
y = y.*t + coeff(k);
end
end

